var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"대회의실, 호텔 아르마다, 샤레이드 지점\\n<color=#ffd34c>크리스티나 브레히트 중사</color>, 연관자 면담 중\\n사태 종료 후 ██시간째.","JPN":"大会議室、ホテルアルマダ、シャレード支店\\n<color=#ffd34c>クリスティーナ・ブレヒト軍曹</color>、関係者面談中\\n事態終了後██時経過。","ENG":"Conference Room, Hotel Armada, Charade branch\\n<color=#ffd34c>Sergeant Christina Brecht</color>, interviewed ██ hours after the incident.","TWN":"大會議室，艾魯瑪達飯店，查雷德據點\\n<color=#ffd34c>克莉絲蒂娜·布萊希特中士</color>，相關人士面談中\\n事件結束後第██個小時","THA":"ห้องประชุม โรงแรมอาร์มาดา สาขาชาเรด\\n<color=#ffd34c>จ่าคริสตินา เบรชต์</color> ให้สัมภาษณ์ ██ ชั่วโมงหลังเกิดเหตุ","VTN":"Phòng Hội nghị, Khách sạn Armada, chi nhánh Charade\\n<color=#ffd34c>Trung sĩ Christina Brecht</color>, được phỏng vấn ██ giờ sau khi vụ việc xảy ra.","SCN":"阿尔马达酒店，查雷德分店大会议室。\\n<color=#ffd34c>克丽丝蒂娜·布雷克特中士</color>，与负责人面谈中\\n事件结束██小时后。","DEU":"Konferenzraum, Hotel Armada, Charade\\n<color=#ffd34c>Unteroffizierin Christina Brecht</color>, ██ Stunden nach dem Vorfall interviewt.","FRA":"Charade, Salle de conférence de l'Hôtel Armada\\n<color=#ffd34c>Sergente Christina Brecht</color>, interrogatoire en cours\\n ██ heures après l'incident."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"올바른 보도, 진실된 정보. 그로니아 국영 뉴스입니다.","JPN":"正しい報道、真なる情報。グロニア国営ニュースです。","ENG":"Reporting in with the truth, Gronia National News.","TWN":"真實的報導，正確的資訊，格羅尼亞國境新聞。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"건국절 기념식의 충격이 채 가시지 않았지만, 온건파 반군은 재난 구획 복구를 지원할 용의가 있다고 밝혔습니다.","JPN":"建国記念式の衝撃がまだ消えておりませんが､反乱軍の穏健派は災難区画の復興を手伝う意向があることを表明しました。","ENG":"The shock of the National Foundation Day incident has not subsided, but the moderate rebels have said they are willing to help rebuild the disaster zone.","TWN":"雖然國慶典禮依舊餘波盪漾，但溫和派叛軍表示有意協助重建災難區劃。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"평화 협정에서 유리한 고지를 차지하기 위한 것으로 보이는 제스처이나, 정부는 이를 환영하며…….","JPN":"平和協定で有利な立場に立つためのものと思われますが､政府はこれを歓迎し……","ENG":"The government welcomes the assistance, though the gesture appears to be aimed at gaining an advantage in the peace agreement.","TWN":"似乎是希望藉此在和平協議中取得優勢，但政府表示歡迎……"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":" 치. 기껏 샤레이드에 왔는데 이게 뭐람.","JPN":"チッ。せっかくシャレードに来たのに何なのよ。","ENG":" Tch. I made it to the Charade, but what a bummer.","TWN":" 嘖，好不容易來一趟查雷德，結果這是怎樣？！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":" 대표는 오자마자 일 있다고 나가 버려, 용돈도 안 줘서 싸구려 여관 방에서 한 발짝도 못 나가. ","JPN":"代表は着いてすぐに仕事で出かけるし、お小遣いもくれないから安っぽい宿から一歩も出られないし。 ","ENG":"Boss left for work as soon as arrived. And she didn't even give me an allowance, so I can’t step out of this shabby hotel room. ","TWN":"BOSS一來就說有事要忙完全不見人影，也沒留零用錢給我，害我只能待在便宜旅館裡！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":" 미안하다는 생각 안 들어, 호라이즌?","JPN":"悪いと思わない､ホライズン？","ENG":" Don’t you feel sorry, Horizon?","TWN":"地平線，你都不會不好意思嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":" 레이첼이 따라와서 발생한 추가 지출을 감안하면 80시간 동안 식사를 수돗물로 대체해도 무방할 겁니다.","JPN":"レイチェルがついてきて発生した追加支出を考えると、80時間分の食事を水道水に変えても問題ないところです。","ENG":" Given additional expenses caused by you, it would be reasonable to replace the meals with tap water for 80 hours.","TWN":"想到你跟來之後會產生的額外支出，可能有80小時都只能喝自來水果腹。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":" 그리고 월급 꼬박꼬박 수령하는 휴먼이 용돈을 요구하지 마십시오.","JPN":"それに毎月給料をもらっているヒューマンはお小遣いを要求しないでください。","ENG":" And you receive your salary on a regular basis. Don’t expect to get an allowance.","TWN":"而且按時領薪水的人類還要求什麼零用錢。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":" 에휴. 한마디도 안 지지, 하여튼.","JPN":"はあ。一言も負けてくれないんだから、まったく。","ENG":" Ugh… You're always trying to score off me.","TWN":"真是的，我講一句你頂十句。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":" ……그런데 진짜 어디 갔다 온 거야? ","JPN":"……で、本当にどこ行ってきたの？ ","ENG":" …Anyway, where have you really been? ","TWN":" ……你說你到底是去哪裡？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":" 여행에서 만난 친구들이라더니 하나같이 본새가 장난 아닌데?","JPN":"旅行であった友達って言ってたけど、全員ヤバい格好してるよ？","ENG":" Are these the ones you met on your journey? They look quite fierce.","TWN":"你說是旅行中遇到的朋友，每個長得都非等閒之輩呢？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"실물을 보니 친구 분 패션도 어떤 의미에서는 파격적이군요, 호라이즌 양.","JPN":"実物を見るとご友人のファッションもある意味では型破りですわね、ホライズンさん。","ENG":"Now that I see her in person, your friend’s fashion sense is rather unconventional, Horizon.","TWN":"見到本人後，發現你朋友的時尚品味算是滿特別的呢，地平線。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"남 말 하지 마십시오. 엘리자베스.","JPN":"人のことを言わないでください、エリザベス。","ENG":"Talk about yourself, Elizabeth.","TWN":"你還敢說別人，伊莉莎白。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"오면서 보니까 이 도시는 진짜 평화롭더라고요. 그냥 눌러앉고 싶어질 정도로요.","JPN":"来る途中で見たら、この街は本当に平和でした。居座りたくなるくらいにですね。","ENG":"Seeing it on the way here, this city seems so peaceful. I’d love to settle down here.","TWN":"來的路上覺得這座城市真的好和平喔，真想在這裡定居。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};